// Package vendor holds the vendoring logic for the hotamspec scenario
// recorder: banner-stamping the canonical source
// (internal/recorder/canon/hotamspec.go) for a copy that will live inside a
// consumer domain's own spec/ Go module, and stripping that banner back off
// for comparison.
//
// This is a DELIBERATELY LEAF package (its only internal import is
// internal/recorder/canon, itself a zero-internal-dependency leaf) so that
// BOTH sides of the vendoring contract can depend on it without an import
// cycle: cmd/hotam's `vendor-recorder` command (via internal/generator)
// WRITES a vendored copy using VendoredRecorderSource, and
// internal/invariants' check_recorder_current READS a vendored copy back
// and compares it using VendoredRecorderBodyForHash + StripVendorBanner.
// Putting this logic directly in internal/generator was tried first and
// rejected: internal/generator already imports internal/diagnose, which
// imports internal/invariants, so internal/invariants importing
// internal/generator (to reach the vendoring helpers) would close a cycle
// (generator -> diagnose -> invariants -> generator). This package sits
// below all three, breaking the cycle structurally rather than by
// reordering which existing package imports which.
package vendor

import (
	"strings"

	hotamspec "github.com/PHPCraftdream/HotamSpec/internal/recorder/canon"
)

// canonicalRecorderSource is the CANONICAL hotamspec recorder source --
// hotamspec.Source, itself a go:embed of internal/recorder/canon/hotamspec.go
// frozen at BUILD time (see that package's embed.go doc comment for why the
// embed lives THERE rather than here: go:embed patterns cannot cross a
// package boundary via "../", so the canon package embeds its own file and
// exports the bytes for this package to import). Referencing hotamspec.Source
// here (rather than re-declaring a second go:embed of the same file) means
// there is exactly ONE embed directive for this file in the whole engine --
// no risk of two copies silently diverging because an edit only touched one
// embed pattern.
//
// Vendoring target: <domainDir>/spec/hotamspec/hotamspec.go, mirroring the
// existing markdown-crystal vendoring precedent (internal/generator/
// claudemd_static.go's static block constants + cmd/hotam/gen_spec.go's
// write-to-docs/gen pattern), applied here to Go source instead of
// Markdown. Unlike the markdown crystal (regenerated on every
// `hotam gen-spec`, unconditionally), the recorder is vendored by a
// SEPARATE, explicit step (cmd/hotam/vendor_recorder.go's
// `hotam vendor-recorder`) rather than folded into gen-spec's own write
// set, because vendoring only makes sense for a domain that already has an
// authored spec/ Go module (PLAN-authored-spec-discipline.md §3) --
// gen-spec runs for every domain, including ones with no spec/ tree at all,
// and it must not try to write a Go file into a directory that is not (yet)
// a Go module.
var canonicalRecorderSource = hotamspec.Source

// Banner is the do-not-edit banner prepended to every vendored copy -- same
// rhetorical shape as spec/.authored-do-not-regenerate (the pilot's own
// existing "this directory is hand-written, the engine never touches it"
// marker) but inverted: this banner marks a file the engine OWNS and
// overwrites on every `hotam vendor-recorder` run, so a human editing it by
// hand is the mistake, not the engine regenerating it. Exported so a caller
// that needs the literal banner text (rather than going through
// Source/StripBanner) can still reach it without re-deriving the string.
const Banner = `// Code generated by ` + "`hotam vendor-recorder`" + `. DO NOT EDIT.
//
// This file is a VENDORED, byte-for-byte copy of HotamSpec's canonical
// internal/recorder/canon/hotamspec.go, generated because this spec/ module
// is a SEPARATE Go module from the HotamSpec engine (PLAN-authored-spec-
// discipline.md's own module-boundary decision: an authored domain's spec/
// tree carries its own go.mod so it never depends on the engine's internal/
// packages, and per NEW-2-bis this engine never wires a cross-module
// ` + "`replace`" + ` directive to bridge that gap). Hand-editing this file will be
// silently discarded the next time ` + "`hotam vendor-recorder`" + ` runs, and a hand
// edit that survives until then is exactly what
// check_recorder_current (internal/invariants) exists to catch: it
// sha256-compares this file's post-banner body against the engine's own
// canon and reports a violation on any drift, whether from a stale
// regeneration or a direct hand edit.
//
// Canonical source: internal/recorder/canon/hotamspec.go (HotamSpec engine
// repository). See that file's own package doc comment for the recorder
// API's design rationale.

`

// Source returns the full byte-for-byte content this spec/ module's
// spec/hotamspec/hotamspec.go should hold: Banner followed by the canonical
// source, UNMODIFIED except that the package clause stays "package
// hotamspec" (already true in the canon -- no rewriting needed, since the
// vendored copy keeps the identical package name so an authored test's
// same-module relative import resolves without any adaptation).
func Source() string {
	return Banner + canonicalRecorderSource
}

// BodyForHash returns ONLY the canonical source bytes (no banner), the exact
// text check_recorder_current hashes on both sides of its comparison (the
// engine's own canon vs. a vendored copy with its banner stripped) -- see
// that check's own doc comment (internal/invariants/recorder_check.go) for
// why the banner itself must be excluded from the hash (it differs from the
// canon file, which carries no banner at all, by construction).
func BodyForHash() string {
	return canonicalRecorderSource
}

// StripBanner removes a leading Banner (if present) from src, returning the
// remainder unchanged. Used by check_recorder_current to recover the
// comparable body from a copy already sitting on disk in a consumer's
// spec/hotamspec/hotamspec.go, without needing to re-derive the banner's
// exact text at the call site. Returns src unchanged (ok=false) if src does
// not start with exactly Banner -- e.g. a hand-edited or never-vendored
// file -- so the caller can distinguish "banner stripped cleanly, body
// comparable" from "this file does not even carry our banner, something is
// structurally wrong before hashing is even meaningful".
func StripBanner(src string) (body string, ok bool) {
	if !strings.HasPrefix(src, Banner) {
		return src, false
	}
	return strings.TrimPrefix(src, Banner), true
}
